fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let n = nums.len();

    // 1. Preprocessing: Store indices where nums[i] is even.
    // P stores usize indices.
    let mut even_indices: Vec<usize> = Vec::new();
    for i in 0..n {
        if nums[i] % 2 == 0 {
            even_indices.push(i);
        }
    }

    // Helper function to find the index of the largest element in nums <= X.
    // Returns -1 if all elements are > X.
    let find_j_max = |x: i64| -> i64 {
        // We search in the range [0, N-1]
        let search_result = nums.binary_search_by(|&val| val.cmp(&x).then(std::cmp::Ordering::Less));

        // If search_result is Ok(i), nums[i] == X. We need the last such index.
        // If search_result is Err(i), nums[i] is the first element > X. The last element <= X is at i-1.

        let mut low = 0;
        let mut high = n; // Search space [low, high)
        let mut j_max = -1;

        // Find the rightmost insertion point for X + 1 (i.e., first element > X)
        while low < high {
            let mid = low + (high - low) / 2;
            if nums[mid] <= x {
                low = mid + 1;
            } else {
                high = mid;
            }
        }

        // low now points to the first element > X, or N if all <= X.
        // The last element <= X is at index low - 1.
        return (low as i64) - 1;
    };

    // Helper function to count removed evens <= X for range [l, r]
    // l, r are 0-indexed i64 values from the query.
    let count_removed_evens = |l: i64, r: i64, x: i64| -> i64 {
        // 1. Find j_max: largest index such that nums[j_max] <= X.
        let j_max = find_j_max(x);

        // If j_max < l, no element in [l, r] can satisfy nums[i] <= X.
        if j_max < l {
            return 0;
        }

        // 2. Determine the effective upper bound for indices in P.
        // We only care about indices i such that l <= i <= r AND i <= j_max.
        let r_bound = std::cmp::min(r, j_max);

        // 3. Count elements in even_indices (P) such that l <= p <= r_bound.

        // Count elements in P <= r_bound
        let count_le_r_bound = even_indices.partition_point(|&p| p as i64 <= r_bound);

        // Count elements in P < l
        // We use l - 1 to find count strictly less than l.
        let count_lt_l = even_indices.partition_point(|&p| p as i64 < l);

        return (count_le_r_bound - count_lt_l) as i64;
    };

    let mut results: Vec<i64> = Vec::with_capacity(queries.len());

    // Max possible answer X: k is up to 10^9. If no evens are removed, X = 2k approx 2*10^9.
    // If max element is 10^9, and we remove all of them, we might need X slightly larger than 2*10^9.
    // 3 * 10^9 + 1 is a safe upper bound. Since i64 goes up to 9*10^18, we use a safe large number.
    let mut max_x = 4_000_000_000i64; 

    for query in queries {
        let l = query[0];
        let r = query[1];
        let k = query[2];

        let mut low = 1i64;
        let mut high = max_x;
        let mut answer = -1i64;

        // Binary Search for the smallest X such that C(X) >= k
        while low <= high {
            let mid = low + (high - low) / 2;

            // 1. Total even numbers <= mid
            let n_total = mid / 2;

            // 2. Removed even numbers <= mid
            let n_removed = count_removed_evens(l, r, mid);

            // 3. Count of remaining evens <= mid
            let c_x = n_total - n_removed;

            if c_x >= k {
                // mid might be the answer, try smaller
                answer = mid;
                high = mid - 1;
            } else {
                // mid is too small, need a larger X
                low = mid + 1;
            }
        }

        results.push(answer);
    }

    results
}

